import{_ as e,c as t,o as n,a1 as o}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"よくある質問: トラブルシューティング | opencode-plannotator","description":"Plannotatorのよくある質問の解決方法を学びます。ポート競合、ブラウザが開かない、連携失敗などの問題を素早く解決するテクニックを習得します。","frontmatter":{"title":"よくある質問: トラブルシューティング | opencode-plannotator","sidebarTitle":"問題が発生したら","subtitle":"よくある質問: トラブルシューティング","description":"Plannotatorのよくある質問の解決方法を学びます。ポート競合、ブラウザが開かない、連携失敗などの問題を素早く解決するテクニックを習得します。","order":4},"headers":[],"relativePath":"ja/backnotprop/plannotator/faq/index.md","filePath":"ja/backnotprop/plannotator/faq/index.md"}'),l={name:"ja/backnotprop/plannotator/faq/index.md"};function i(r,a,s,p,d,c){return n(),t("div",null,[...a[0]||(a[0]=[o(`<h1 id="よくある質問" tabindex="-1">よくある質問 <a class="header-anchor" href="#よくある質問" aria-label="Permalink to &quot;よくある質問&quot;">​</a></h1><p>この章では、Plannotatorの使用中に発生するさまざまな問題の解決をサポートします。ポート競合、ブラウザが開かない、連携失敗など、あらゆる問題に対応する解決策とデバッグテクニックを紹介します。</p><h2 id="この章の内容" tabindex="-1">この章の内容 <a class="header-anchor" href="#この章の内容" aria-label="Permalink to &quot;この章の内容&quot;">​</a></h2><div class="grid-cards"><a href="./common-problems/" class="card"><h3>🔧 よくある問題</h3><p>使用中に発生するよくある問題を解決します。ポート競合、ブラウザが開かない、プランが表示されない、Gitエラー、画像アップロード失敗、Obsidian/Bear連携の問題などを含みます。</p></a><a href="./troubleshooting/" class="card"><h3>🔍 トラブルシューティング</h3><p>トラブルシューティングの基本的な方法を習得します。ログの確認、エラー処理、デバッグテクニックを学び、ログ出力から問題の原因を素早く特定できるようになります。</p></a></div><h2 id="学習パス" tabindex="-1">学習パス <a class="header-anchor" href="#学習パス" aria-label="Permalink to &quot;学習パス&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>よくある問題 → トラブルシューティング</span></span>
<span class="line"><span>    ↓              ↓</span></span>
<span class="line"><span> 素早く解決     詳細なデバッグ</span></span></code></pre></div><p><strong>推奨順序</strong>：</p><ol><li><strong>まずよくある問題を確認</strong>：ほとんどの問題はここで既存の解決策が見つかります</li><li><strong>次にトラブルシューティングを学習</strong>：よくある問題でカバーされていない場合、ログとデバッグテクニックを使って自分で調査する方法を学びます</li></ol><div class="tip custom-block"><p class="custom-block-title">問題が発生したときのアドバイス</p><p>まず「よくある問題」でキーワード（「ポート」「ブラウザ」「Obsidian」など）を検索し、対応する解決策を見つけてください。問題が複雑な場合やリストにない場合は、「トラブルシューティング」を参照してデバッグ方法を学びましょう。</p></div><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><p>この章を学習する前に、以下を完了していることを推奨します：</p><ul><li>✅ <a href="./../start/getting-started/">クイックスタート</a> - Plannotatorの基本概念を理解</li><li>✅ Claude CodeまたはOpenCodeプラグインのインストール（いずれか一方）： <ul><li><a href="./../start/installation-claude-code/">Claude Codeプラグインのインストール</a></li><li><a href="./../start/installation-opencode/">OpenCodeプラグインのインストール</a></li></ul></li></ul><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>この章を完了したら、以下の学習に進めます：</p><ul><li><a href="./../appendix/api-reference/">APIリファレンス</a> - すべてのAPIエンドポイントとリクエスト/レスポンス形式を理解</li><li><a href="./../appendix/data-models/">データモデル</a> - Plannotatorで使用されるデータ構造を理解</li><li><a href="./../advanced/environment-variables/">環境変数の設定</a> - 利用可能なすべての環境変数を詳しく理解</li></ul>`,15)])])}const b=e(l,[["render",i]]);export{u as __pageData,b as default};
